# order/domain/entities/order.py
from dataclasses import dataclass, field
from datetime import datetime
from decimal import Decimal
from enum import Enum
from typing import List
from uuid import UUID, uuid4

from .value_objects import Money, Address
from .events import OrderPlaced, OrderShipped


class OrderStatus(Enum):
    DRAFT = "draft"
    PLACED = "placed"
    PAID = "paid"
    SHIPPED = "shipped"
    DELIVERED = "delivered"
    CANCELLED = "cancelled"


@dataclass
class OrderLine:
    """Value object representing an order line item."""
    product_id: UUID
    product_name: str
    quantity: int
    unit_price: Money

    @property
    def total(self) -> Money:
        return Money(self.unit_price.amount * self.quantity, self.unit_price.currency)


@dataclass
class Order:
    """Order aggregate root."""

    id: UUID = field(default_factory=uuid4)
    customer_id: UUID = field(default=None)
    status: OrderStatus = OrderStatus.DRAFT
    lines: List[OrderLine] = field(default_factory=list)
    shipping_address: Address = None
    placed_at: datetime = None
    _events: List = field(default_factory=list, repr=False)

    def add_line(self, product_id: UUID, name: str, quantity: int, price: Money) -> None:
        """Add a line item to the order."""
        if self.status != OrderStatus.DRAFT:
            raise DomainError("Cannot modify a placed order")
        if quantity <= 0:
            raise DomainError("Quantity must be positive")
        for line in self.lines:
            if line.product_id == product_id:
                raise DomainError("Product already in order")
        self.lines.append(OrderLine(product_id, name, quantity, price))

    def remove_line(self, product_id: UUID) -> None:
        """Remove a line item from the order."""
        if self.status != OrderStatus.DRAFT:
            raise DomainError("Cannot modify a placed order")
        self.lines = [l for l in self.lines if l.product_id != product_id]

    def place(self, shipping_address: Address) -> None:
        """Place the order."""
        if self.status != OrderStatus.DRAFT:
            raise DomainError("Order already placed")
        if not self.lines:
            raise DomainError("Cannot place empty order")
        self.shipping_address = shipping_address
        self.status = OrderStatus.PLACED
        self.placed_at = datetime.utcnow()
        self._events.append(OrderPlaced(
            order_id=self.id,
            customer_id=self.customer_id,
            total=self.total,
        ))

    def mark_paid(self) -> None:
        """Mark order as paid."""
        if self.status != OrderStatus.PLACED:
            raise DomainError("Order must be placed before payment")
        self.status = OrderStatus.PAID

    def ship(self, tracking_number: str) -> None:
        """Ship the order."""
        if self.status != OrderStatus.PAID:
            raise DomainError("Order must be paid before shipping")
        self.status = OrderStatus.SHIPPED
        self._events.append(OrderShipped(
            order_id=self.id,
            tracking_number=tracking_number,
        ))

    def cancel(self) -> None:
        """Cancel the order."""
        if self.status in (OrderStatus.SHIPPED, OrderStatus.DELIVERED):
            raise DomainError("Cannot cancel shipped order")
        self.status = OrderStatus.CANCELLED

    @property
    def total(self) -> Money:
        """Calculate order total."""
        if not self.lines:
            return Money(Decimal("0"), "USD")
        total = sum(line.total.amount for line in self.lines)
        return Money(total, self.lines[0].unit_price.currency)

    def collect_events(self) -> List:
        events = self._events.copy()
        self._events.clear()
        return events

# BAD: just data, no behavior
class Order:
    def __init__(self):
        self.id = None
        self.status = None
        self.lines = []

class OrderService:
    def place_order(self, order):
        # Invariants scattered across service methods; easy to forget
        order.status = "placed"

# BAD: reaching into another aggregate's internals
class Order:
    def place(self):
        # Never access another aggregate's internal state
        if self.customer.wallet.balance < self.total:
            raise Error("Insufficient funds")

# GOOD: use application service to coordinate
class PlaceOrderUseCase:
    async def execute(self, order_id, customer_id):
        order = await self.order_repo.find(order_id)
        customer = await self.customer_repo.find(customer_id)
        if not customer.can_afford(order.total):
            raise InsufficientFundsError()
        order.place()

# tests/domain/test_order.py import pytest from decimal import Decimal from order.domain.entities.order import Order, OrderStatus from order.domain.value_objects import Money, Address
def test_cannot_place_empty_order(): order = Order(customer_id="c-1") with pytest.raises(DomainError, match="empty"): order.place(shipping_address=_addr())
def test_place_emits_event(): order = Order(customer_id="c-1") order.add_line("p-1", "X", 1, Money(Decimal("10"), "USD")) order.place(shipping_address=_addr()) events = order.collect_events() assert len(events) == 1 assert events[0].order_id == order.id
def test_cannot_modify_after_place(): order = Order(customer_id="c-1") order.add_line("p-1", "X", 1, Money(Decimal("10"), "USD")) order.place(_addr()) with pytest.raises(DomainError, match="placed"): order.add_line("p-2", "Y", 1, Money(Decimal("5"), "USD"))
def _addr(): return Address("1 Main", "City", "ST", "12345", "US")
